// Estoque mínimo definido pelo Fabrício para cada tipo de camisa/tamanho
function estoqueMinimo(p){
  const time=(p.time||p.nome||"").toLowerCase();
  const tam=(p.tamanho||"").toUpperCase();
  const uni=(p.uniforme||"").toLowerCase();
  // Retrô: 1 de cada (G e GG)
  if(time.includes("retrô")||time.includes("retro")){
    return 1;
  }
  // Uniformes avulsos: 1 de cada
  if(uni.includes("uniforme 2")){return 1;}
  // Bahia e Vitória: M=1, G=2, GG=2
  if(time.includes("bahia")||time.includes("vitória")||time.includes("vitoria")){
    if(tam==="M")return 1;
    if(tam==="G"||tam==="GG")return 2;
    return 1;
  }
  // Padrão: usa qtdMin salvo ou 1
  return p.qtdMin||1;
}
function isBaixo(p){return p.qtd<estoqueMinimo(p);}
